SIGS = {
    b'\x89PNG': 'PNG', b'\xff\xd8\xff': 'JPEG',
    b'%PDF': 'PDF', b'PK\x03\x04': 'ZIP',
    b'MZ': 'EXE', b'\x7fELF': 'Linux ELF',
}

def identify(data):
    for sig, name in SIGS.items():
        if data.startswith(sig):
            return name
    return 'Unknown'

print(identify(b'\x89PNG\r\n\x1a\n'))  # PNG
print(identify(b'MZ\x90\x00'))          # EXE

def xor_crypt(data, key):
    if isinstance(key, int):
        return bytes([b ^ key for b in data])
    return bytes([b ^ key[i%len(key)] for i,b in enumerate(data)])

secret = b'HIDDEN MESSAGE'
enc = xor_crypt(secret, 0x42)
print(f'Encrypted: {enc.hex()}')
dec = xor_crypt(enc, 0x42)
print(f'Decrypted: {dec.decode()}')

