import base64, re

def encode_b64(text):
    return base64.b64encode(text.encode()).decode()

def decode_b64(b64):
    try: return base64.b64decode(b64).decode('utf-8', errors='replace')
    except: return '[decode error]'

print('=== Base64 Encoding ===')
for msg in ['Hello World', 'admin:secret', '{"role":"admin"}']:
    enc = encode_b64(msg)
    print(f'{msg:30s} -> {enc}')

print('\n=== Detecting Hidden Base64 ===')
log = '''2024-01-15 Login attempt
Payload: SGVsbG8gV29ybGQ=
Cookie: eyJ1c2VyIjoiYWRtaW4ifQ==
Normal text here'''

for match in re.findall(r'[A-Za-z0-9+/]{16,}={0,2}', log):
    print(f'Found: {match}')
    print(f'Decoded: {decode_b64(match)}')

def xor_encrypt(data, key):
    if isinstance(data, str): data = data.encode()
    if isinstance(key, int): return bytes([b ^ key for b in data])
    if isinstance(key, str): key = key.encode()
    return bytes([b ^ key[i%len(key)] for i,b in enumerate(data)])

def brute_force_xor(encrypted):
    results = []
    for key in range(256):
        dec = bytes([b ^ key for b in encrypted])
        score = sum(1 for b in dec if 32<=b<127) / len(dec)
        results.append((key, dec, score))
    results.sort(key=lambda x: x[2], reverse=True)
    return results

print('=== XOR Encrypt/Decrypt ===')
secret = b'FORENSIC EVIDENCE'
enc = xor_encrypt(secret, 0x4B)
print(f'Encrypted: {enc.hex()}')
print(f'Decrypted: {xor_encrypt(enc, 0x4B).decode()}')

print('\n=== Brute-Force Cracking ===')
for key, plaintext, score in brute_force_xor(enc)[:3]:
    print(f'Key 0x{key:02X}: {plaintext.decode("ascii",errors="."):<25s} [{score:.0%}]')

import base64, re, math

class Analyser:
    SIGS = [(b'\x89PNG','PNG'),(b'\xff\xd8\xff','JPEG'),(b'%PDF','PDF'),
            (b'PK\x03\x04','ZIP'),(b'MZ','PE/EXE'),(b'\x7fELF','ELF')]

    def __init__(self, data):
        self.data = data

    def file_type(self):
        for sig,name in self.SIGS:
            if self.data.startswith(sig): return name
        return 'Unknown'

    def strings(self, min_len=4):
        return [m.decode() for m in re.findall(rb'[\x20-\x7E]{%d,}'%min_len, self.data)]

    def emails(self):
        return [m.decode() for m in re.findall(rb'[\w.+-]+@[\w.-]+\.\w{2,}', self.data)]

    def urls(self):
        return [m.decode() for m in re.findall(rb'https?://[^\s\x00<>]+', self.data)]

    def entropy(self):
        if not self.data: return 0
        freq = [0]*256
        for b in self.data: freq[b] += 1
        return -sum(p*math.log2(p) for c in freq if c>0 for p in [c/len(self.data)])

    def report(self):
        print(f'Size: {len(self.data):,}B | Type: {self.file_type()}')
        ent = self.entropy()
        label = 'encrypted' if ent>7.5 else 'mixed' if ent>5 else 'text'
        print(f'Entropy: {ent:.2f}/8.0 ({label})')
        for s in self.strings()[:8]: print(f'  STR: "{s}"')
        for e in self.emails(): print(f'  EMAIL: {e}')
        for u in self.urls(): print(f'  URL: {u}')

