evidence += b'Contact: suspect@dark.onion\n'
evidence += b'C2: http://10.13.37.100:4444/shell\n'
evidence += b'Auth: ' + base64.b64encode(b'admin:p@ss') + b'\n'

Analyser(evidence).report()

