def to_decimal(binary_str):
    total = 0
    for i, bit in enumerate(reversed(binary_str)):
        total += int(bit) * (2 ** i)
    return total

def hex_to_dec(hex_str):
    digits = '0123456789ABCDEF'
    total = 0
    for i, ch in enumerate(reversed(hex_str.upper())):
        total += digits.index(ch) * (16 ** i)
    return total

def show_all_bases(n):
    asc = chr(n) if 32 <= n < 127 else '(non-printable)'
    print(f'Dec: {n}  Bin: {bin(n)}  Hex: {hex(n)}  Oct: {oct(n)}  ASCII: {asc}')

def byte_range(n):
    if n <= 0xFF:
        print(f'{n} fits in 1 byte ({hex(n)})')
    elif n <= 0xFFFF:
        print(f'{n} fits in 2 bytes ({hex(n)})')
    elif n <= 0xFFFFFFFF:
        print(f'{n} fits in 4 bytes ({hex(n)})')
    else:
        print(f'{n} needs more than 4 bytes!')

def ascii_values(text):
    for ch in text:
        print(f'{ch} -> Dec: {ord(ch)}, Hex: 0x{ord(ch):02X}')

def toggle_case(text):
    result = ''
    for ch in text:
        c = ord(ch)
        if 65 <= c <= 90: result += chr(c + 32)
        elif 97 <= c <= 122: result += chr(c - 32)
        else: result += ch
    return result

def caesar(text, shift):
    result = ''
    for ch in text:
        if 'A' <= ch <= 'Z':
            result += chr((ord(ch) - 65 + shift) % 26 + 65)
        elif 'a' <= ch <= 'z':
            result += chr((ord(ch) - 97 + shift) % 26 + 97)
        else:
            result += ch
    return result

def crack_caesar(ct):
    for s in range(26):
        result = ''
        for ch in ct:
            if 'A'<=ch<='Z': result += chr((ord(ch)-65-s)%26+65)
            elif 'a'<=ch<='z': result += chr((ord(ch)-97-s)%26+97)
            else: result += ch
        print(f'Shift {s:2d}: {result}')

def char_frequency(text):
    freq = {}
    for ch in text: freq[ch] = freq.get(ch, 0) + 1
    total = len(text)
    for ch, count in sorted(freq.items(), key=lambda x: -x[1]):
        print(f'{ch}: {count} ({count/total*100:.1f}%)')

def rot13(text):
    result = ''
    for ch in text:
        if 'A'<=ch<='Z': result += chr((ord(ch)-65+13)%26+65)
        elif 'a'<=ch<='z': result += chr((ord(ch)-97+13)%26+97)
        else: result += ch
    return result

def detect_non_ascii(text):
    found = False
    for i, ch in enumerate(text):
        if ord(ch) > 127:
            print(f'Position {i}: {ch!r} (U+{ord(ch):04X}) - NOT ASCII')
            found = True
    if not found:
        print('All characters are ASCII')

def encode_hex(msg):
    return ' '.join(f'{ord(c):02X}' for c in msg)

def decode_hex(hx):
    return ''.join(chr(int(h, 16)) for h in hx.split())

def simple_hex(data):
    for i in range(0, len(data), 16):
        chunk = data[i:i+16]
        hx = ' '.join(f'{b:02x}' for b in chunk)
        print(f'{i:08x}  {hx}')

def hex_dump(data, width=16):
    for i in range(0, len(data), width):
        chunk = data[i:i+width]
        hx = ' '.join(f'{b:02x}' for b in chunk)
        asc = ''.join(chr(b) if 32<=b<127 else '.' for b in chunk)
        print(f'{i:08x}  {hx:<{width*3}}  |{asc}|')

