import re
def detect_encoding(text):
    if re.search(r'%[0-9A-Fa-f]{2}', text):
        kind = 'Likely URL-encoded'
    elif re.match(r'^[A-Za-z0-9+/]{4,}={0,2}$', text) and len(text)%4==0:
