def encode_chain(text, steps):
    data = text
    for step in steps:
        if step=='base64': data=base64.b64encode((data if isinstance(data,bytes) else data.encode())).decode()
        elif step=='url': data=urllib.parse.quote(str(data))
        elif step=='hex': data=(data if isinstance(data,bytes) else data.encode()).hex()
        print(f'  After {step}: {data}')
