def hamming_distance(b1, b2):
    return sum(bin(a^b).count('1') for a,b in zip(b1,b2))

def guess_key_length(encrypted, max_len=20):
    scores = []
    for kl in range(2, min(max_len+1, len(encrypted)//2)):
        block1 = encrypted[:kl]
        block2 = encrypted[kl:2*kl]
        dist = hamming_distance(block1, block2) / kl
        scores.append((kl, dist))
