def carve_files(data):
    sigs = [(b'\x89PNG','PNG'),(b'%PDF','PDF'),(b'MZ','EXE'),(b'\xff\xd8\xff','JPEG')]
    found = []
    for sig,name in sigs:
        pos = 0
        while True:
            idx = data.find(sig, pos)
            if idx == -1: break
            found.append((idx, name))
            pos = idx + 1
    found.sort()
    for i,(off,name) in enumerate(found):
        end = found[i+1][0] if i+1<len(found) else len(data)
        size = end - off
        print(f'Found {name} at offset {off} ({size} bytes)')
    print(f'Total: {len(found)} files carved')
